import type { IconProps } from '@/components/icons/types'
import { DEFAULT_ICON_SIZE } from '@/components/icons/types'
/**
 * Общие UI-иконки из assets: like, dislike, plus, minus, reply, send, comment и др.
 */
import { useId } from 'react'

const iconProps = (p: IconProps) => {
  const size = p.size ?? DEFAULT_ICON_SIZE
  const color = p.color ?? 'currentColor'
  return { width: size, height: size, className: p.className, color }
}

/** Лайк (like.svg) — для плюса в комментариях */
export function IconLike(props: IconProps) {
  const { color, ...rest } = iconProps(props)
  return (
    <svg viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg" {...rest}>
      <path
        d="M5.95 2.5C3.21625 2.5 1 4.65216 1 7.30685C1 12.1137 6.85 16.4836 10 17.5C13.15 16.4836 19 12.1137 19 7.30685C19 4.65216 16.7837 2.5 14.05 2.5C12.376 2.5 10.8955 3.30711 10 4.54248C9.54348 3.9112 8.93708 3.396 8.23211 3.04048C7.52715 2.68495 6.74436 2.49956 5.95 2.5Z"
        fill={color}
        stroke={color}
        strokeWidth="1.66667"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  )
}

